import React, { useEffect, useState } from 'react';
import './item.css';
import Image from './phonk_wallpaper.jpg';

function ItemPage() {
  const [items, setItems] = useState([]);

  useEffect(() => {
    async function loadItems() {
      try {
        const response = await fetch("http://localhost:8000/api/items/");
        const data = await response.json();
        setItems(data);
      } catch (error) {
        console.error("Ошибка загрузки предметов:", error);
      }
    }

    loadItems();
  }, []);

  return (
    <div id="content_items">

      <div id="popular_item_card">
        <p id="popular_item_card_text">Популярное</p>
        <img src={Image} alt="Ну нету авы, я что сделаю!" id="popular_item_card_img" />
        <img src={Image} alt="Ну нету авы, я что сделаю!" id="popular_item_card_img" />
        <img src={Image} alt="Ну нету авы, я что сделаю!" id="popular_item_card_img" />
      </div>

      {items.length === 0 && (
        <div id="item_card">
          <p id="item_card_name">Предметов пока нет</p>
          <p id="item_card_text">Зайдите позже</p>
        </div>
      )}

      {items.map(item => (
        <div id="item_card" key={item.id}>
          <p id="item_card_title">{item.title}</p>

          <p id="item_card_text">{item.description}</p>

          <img
            src={Image}
            alt="Ну нету авы, я что сделаю!"
            id="item_card_img"
          />

          <p id="item_card_text">Редкость: {item.rarity}</p>
          <p id="item_card_text">Цена: {item.price} ₽</p>
        </div>
      ))}

    </div>
  );
}

export default ItemPage;
